class AuthSettings(BaseSettings):
    """JWT verification material for the AgentOS auth gate.

  At least one of ``jwks_url``, ``jwt_secret``, or ``jwt_verification_keys`` must be set.
  Supabase: set exactly one of ``jwks_url`` (RS256 JWKS) or ``jwt_secret`` (HS256).
  Agno / other RS256 issuers: add PEM public keys via ``JWT_VERIFICATION_KEYS`` and/or
  ``JWT_VERIFICATION_KEY`` (merged into ``jwt_verification_keys``).
    """

    model_config = SettingsConfigDict(frozen=True)

    audience: str = Field(default="authenticated", validation_alias="SUPABASE_JWT_AUDIENCE")
    admin_scope: str = Field(default="agent_os:admin", validation_alias="SUPABASE_JWT_ADMIN_SCOPE")

    jwks_url: str | None = Field(default=None, validation_alias="SUPABASE_JWKS_URL")
    jwt_secret: str | None = Field(default=None, validation_alias="SUPABASE_JWT_SECRET")
    jwt_verification_keys: list[str] = Field(
        default_factory=list, validation_alias="JWT_VERIFICATION_KEYS"
    )

    @field_validator("jwt_verification_keys", mode="before")
    @classmethod
    def _parse_jwt_verification_keys(cls, value: object) -> list[str]:
        if value is None or value == "":
            return []
        if isinstance(value, list):
            return [str(item).strip() for item in value if str(item).strip()]
        if isinstance(value, str):
            raw = value.strip()
            if not raw:
                return []
            if raw.startswith("["):
                parsed = json.loads(raw)
                if not isinstance(parsed, list):
                    raise ValueError("JWT_VERIFICATION_KEYS must be a JSON array of strings")
                return [str(item).strip() for item in parsed if str(item).strip()]
            return [part.strip() for part in raw.split(",") if part.strip()]
        raise TypeError(f"JWT_VERIFICATION_KEYS: unexpected type {type(value)!r}")

    @property
    def algorithm(self) -> str:
        if self.jwt_secret and not self.jwks_url:
            return "HS256"
        return "RS256"

    @property
    def verification_keys(self) -> list[str]:
        """RS256 PEM public keys (Agno control plane, etc.), including ``JWT_VERIFICATION_KEY``."""
        keys = list(self.jwt_verification_keys)
        single = os.environ.get("JWT_VERIFICATION_KEY", "").strip()
        if single and single not in keys:
            keys.append(single)
        return keys

    def model_post_init(self, __context: object) -> None:
        has_jwks = bool(self.jwks_url)
        has_secret = bool(self.jwt_secret)
        has_pem_keys = bool(self.verification_keys)
        if not has_jwks and not has_secret and not has_pem_keys:
            raise ValueError(
                "AuthSettings: set at least one of SUPABASE_JWKS_URL, SUPABASE_JWT_SECRET, "
                "or JWT_VERIFICATION_KEYS / JWT_VERIFICATION_KEY."
            )
        if has_jwks and has_secret:
            raise ValueError(
                "AuthSettings: set exactly one of SUPABASE_JWKS_URL or SUPABASE_JWT_SECRET; "
                "both are set — remove one."
            )

