@staticmethod
def _normalize_pem(value: str) -> str:
    """Accept PEM as pasted (with real or ``\\n``-escaped newlines)."""
    pem = value.strip().replace("\\n", "\n")
    if "-----BEGIN" not in pem:
        return pem
    return pem

@property
def verification_keys(self) -> list[str]:
    """RS256 PEM public keys (Agno control plane, etc.).

    Sources: ``JWT_VERIFICATION_KEYS``, ``JWT_VERIFICATION_KEY`` (single line or
    ``\\n``-escaped), ``JWT_VERIFICATION_KEY_FILE`` (multiline PEM file).
    """
    keys: list[str] = [
        self._normalize_pem(item) for item in self.jwt_verification_keys if item.strip()
    ]

    single = os.environ.get("JWT_VERIFICATION_KEY", "").strip()
    if single:
        normalized = self._normalize_pem(single)
        if normalized not in keys:
            keys.append(normalized)

    key_file = os.environ.get("JWT_VERIFICATION_KEY_FILE", "").strip()
    if key_file:
        pem = self._normalize_pem(Path(key_file).read_text(encoding="utf-8"))
        if pem not in keys:
            keys.append(pem)

    return keys
